        const ANSI_REGEX = /[\u001B\u009B][[()#;?]*(?:[0-9]{1,4}(?:;[0-9]{0,4})*)?[0-9A-ORZcf-nqry=><]/g;
        const visibleLen = (s: string) => s.replace(ANSI_REGEX, '').length;
        const frameWidth = Math.max(...lines.map(l => visibleLen(l)));
