export function formatarListaArquivos(arquivos: string[], maxExibir: number = 10): string[] {
  const linhas: string[] = [];
  const mostrar = arquivos.slice(0, maxExibir);
  for (const arquivo of mostrar) {
    linhas.push(`   ${ICONES_ZELADOR.arquivo} ${arquivo}`);
  }
