  // Caso especial: se plugins foram passados e o parser de .ts/.tsx retornou null,
  // força fallback para o compilador TS (cobre cenários de plugins conflitantes como 'flow').
  if (parseResultado === null && opts.plugins && (ext === '.ts' || ext === '.tsx')) {
    const tsx = ext === '.tsx';
    const tsParsed = parseComTypeScript(codigo, tsx);
    if (tsParsed) {
      setCurrentParsingFile(undefined);
      return Promise.resolve(tsParsed as unknown as BabelFile);
    }
  }
  if (opts.timeoutMs) {
    return (async () => {
      let timer: NodeJS.Timeout | null = null;
      try {
        const race = Promise.race([Promise.resolve(parseResultado), new Promise<null>((resolve) => {
          timer = setTimeout(() => {
            logCore.timeoutParsing(opts.timeoutMs || 0, ext);
            resolve(null);
          }, opts.timeoutMs);
        })]);
        return await race;
      } finally {
        if (timer) clearTimeout(timer);
        setCurrentParsingFile(undefined);
      }
    })();
  }

  // Se ainda assim for null, normalize para null explícito
  setCurrentParsingFile(undefined);
  return Promise.resolve(parseResultado ?? null);
}
function initializePluginSystem() {
  const registry = getGlobalRegistry();

  // Registra todos os plugins padrão se ainda não foram registrados
  const registeredPlugins = registry.getRegisteredPlugins();
  if (registeredPlugins.length === 0) {
    initializeDefaultPlugins();
    log.debug(ParserExtraMensagens.pluginsRegistrados);
  }
}

/**
 * Parse usando o novo sistema de plugins (API futura)
 * Mantém compatibilidade com sistema atual
 */

export async function parseComPlugins(codigo: string, extensao: string, opts?: PluginParserOptions): Promise<BabelFile | null> {
  try {
    initializePluginSystem();
    const registry = getGlobalRegistry();
    const plugin = await registry.getPluginForExtension(extensao);
    if (!plugin) {
      logCore.pluginNaoEncontrado(extensao);
      // Fallback para sistema atual usando a função exportada
      return await decifrarSintaxe(codigo, extensao, {
        plugins: opts?.plugins,
        timeoutMs: opts?.timeoutMs
      });
    }
    logCore.usandoPlugin(plugin.name, extensao);
    const pluginOpts: PluginParserOptions = {
      ...opts,
      pluginConfig: {
        ...opts?.pluginConfig,
        extension: extensao
      }
    };
    const result = await plugin.parse(codigo, pluginOpts);
    return result;
  } catch (error) {
    logCore.sistemaPluginsFalhou((error as Error).message);
    // Fallback para sistema atual em caso de erro
    return await decifrarSintaxe(codigo, extensao, {
      plugins: opts?.plugins,
      timeoutMs: opts?.timeoutMs
    });
  }
}

/**
 * Obtém estatísticas do sistema de plugins
 */

export function getPluginStats(): {
  pluginsRegistrados: number;
  extensoesSuportadas: number;
  sistemAtivojava: boolean;
} {
  try {
    initializePluginSystem();
    const registry = getGlobalRegistry();
    const stats = registry.getStats();
    return {
      pluginsRegistrados: stats.pluginsRegistrados,
      extensoesSuportadas: stats.extensoesSuportadas,
      sistemAtivojava: stats.pluginsRegistrados > 0
    };
  } catch {
    return {
      pluginsRegistrados: 0,
      extensoesSuportadas: 0,
      sistemAtivojava: false
    };
  }
}

// SPDX-License-Identifier: MIT
/**
 * @fileoverview Registry centralizado para operações de leitura/escrita de arquivos JSON
 *
 * Este módulo fornece uma camada de abstração sobre a persistência,
 * gerenciando migrações automáticas de arquivos legados e garantindo
 * que todos os arquivos sejam salvos nos locais corretos.
 *
 * Features:
 * - Migração automática de arquivos legados
 * - Validação de integridade de JSONs
 * - Logging de operações de I/O
 * - Fallback para configurações seguras
 */
import { promises as fs } from 'node:fs';
import path from 'node:path';

import type { MigrationResult } from '@prometheus';

import { messages } from '../messages/index.js';
import { MIGRACAO_MAPA,PROMETHEUS_ARQUIVOS, PROMETHEUS_DIRS, type PrometheusFilePath } from './paths.js';

const log = messages.log;

/**
 * Opções para operações de leitura
 */
interface ReadOptions<T> {
  /** Valor padrão se arquivo não existir */
  default?: T;
  /** Tentar migrar de arquivo legado automaticamente */
  migrate?: boolean;
  /** Validar estrutura do JSON */
  validate?: (data: unknown) => data is T;
}

/**
 * Opções para operações de escrita
 */
interface WriteOptions {
  /** Criar diretórios pai se não existirem */
  createDirs?: boolean;
  /** Fazer backup antes de sobrescrever */
  backup?: boolean;
  /** Pretty print JSON */
  pretty?: boolean;
}

/**
 * Verifica se arquivo existe
 */
async function fileExists(fileCaminho: string): Promise<boolean> {
  try {
    await fs.access(fileCaminho);
    return true;
  } catch {
    return false;
  }
}

/**
 * Cria diretórios pai se não existirem
 */
async function ensureDir(fileCaminho: string): Promise<void> {
  const dir = path.dirname(fileCaminho);
  await fs.mkdir(dir, {
    recursive: true
  });
}

/**
 * Tenta migrar arquivo legado para novo local
 */
async function tryMigrate(targetPath: string): Promise<MigrationResult> {
  const legacyCaminho = Object.entries(MIGRACAO_MAPA).find(([_, target]) => target === targetPath)?.[0];
  if (!legacyCaminho) {
    return {
      migrated: false
    };
  }
  const legacyExists = await fileExists(legacyCaminho);
  if (!legacyExists) {
    return {
      migrated: false
    };
  }
  try {
    // Ler arquivo legado
    const content = await fs.readFile(legacyCaminho, 'utf-8');

    // Garantir diretório de destino
    await ensureDir(targetPath);

    // Escrever no novo local
    await fs.writeFile(targetPath, content, 'utf-8');

    // Renomear arquivo legado (não deletar para segurança)
    const backupCaminho = `${legacyCaminho}.migrated`;
    await fs.rename(legacyCaminho, backupCaminho);
    log.info(`Migração automática: ${path.basename(legacyCaminho)} → ${path.basename(targetPath)}`);
    return {
      migrated: true,
      from: legacyCaminho,
      to: targetPath
    };
  } catch (erro) {
    log.aviso(`Falha na migração de ${legacyCaminho}: ${(erro as Error).message}`);
    return {
      migrated: false
    };
  }
}

/**
 * Lê arquivo JSON do registry
 *
 * @param filePath Caminho do arquivo (use PROMETHEUS_FILES.*)
 * @param options Opções de leitura
 * @returns Conteúdo parseado do JSON
 *
 * @example
 * ```ts
 * const config = await readJSON(PROMETHEUS_FILES.CONFIG, {
 *   default: {}
 * });
 * ```
 */
export async function readJSON<T = unknown>(fileCaminho: PrometheusFilePath | string, options: ReadOptions<T> = {}): Promise<T> {
  const {
    default: defaultValue,
    migrate = true,
    validate
  } = options;
  try {
    // Tentar migração se habilitado
    if (migrate) {
      const migration = await tryMigrate(fileCaminho);
      if (migration.migrated && migration.to) {
        // Usar arquivo migrado
        fileCaminho = migration.to;
      }
    }

    // Verificar existência
    const exists = await fileExists(fileCaminho);
    if (!exists) {
      if (defaultValue !== undefined) {
        return defaultValue;
      }
      throw new Error(messages.ExcecoesMensagens.arquivoNaoEncontrado(String(fileCaminho)));
    }

    // Ler e parsear
    const content = await fs.readFile(fileCaminho, 'utf-8');
    const parsed = JSON.parse(content) as T;

    // Validar se fornecido
    if (validate && !validate(parsed)) {
      throw new Error(messages.ExcecoesMensagens.validacaoFalhouPara(String(fileCaminho)));
    }
    return parsed;
  } catch (erro) {
    if (defaultValue !== undefined) {
      return defaultValue;
    }
    throw new Error(messages.ExcecoesMensagens.erroAoLer(String(fileCaminho), (erro as Error).message));
  }
}

/**
 * Escreve arquivo JSON no registry
 *
 * @param filePath Caminho do arquivo (use PROMETHEUS_FILES.*)
 * @param data Dados a serem salvos
 * @param options Opções de escrita
 *
 * @example
 * ```ts
 * await writeJSON(PROMETHEUS_FILES.GUARDIAN_BASELINE, snapshot, {
 *   createDirs: true,
 *   backup: true
 * });
 * ```
 */
export async function writeJSON<T = unknown>(fileCaminho: PrometheusFilePath | string, data: T, options: WriteOptions = {}): Promise<void> {
  const {
    createDirs = true,
    backup = false,
    pretty = true
  } = options;
  try {
    // Criar diretórios se necessário
    if (createDirs) {
      await ensureDir(fileCaminho);
    }

    // Fazer backup se solicitado
    if (backup && (await fileExists(fileCaminho))) {
      const backupCaminho = `${fileCaminho}.backup`;
      await fs.copyFile(fileCaminho, backupCaminho);
    }

    // Serializar JSON
    const content = pretty ? JSON.stringify(data, null, 2) : JSON.stringify(data);

    // Escrever arquivo
    await fs.writeFile(fileCaminho, content, 'utf-8');
  } catch (erro) {
    throw new Error(messages.ExcecoesMensagens.erroAoEscrever(String(fileCaminho), (erro as Error).message));
  }
}

/**
 * Deleta arquivo do registry
 *
 * @param filePath Caminho do arquivo (use PROMETHEUS_FILES.*)
 * @param options Opções de deleção
 */
export async function deleteJSON(fileCaminho: PrometheusFilePath | string, options: {
  backup?: boolean;
} = {}): Promise<void> {
  const {
    backup = true
  } = options;
  try {
    const exists = await fileExists(fileCaminho);
    if (!exists) {
      return; // Já deletado
    }
    if (backup) {
      const backupCaminho = `${fileCaminho}.deleted`;
      await fs.rename(fileCaminho, backupCaminho);
    } else {
      await fs.unlink(fileCaminho);
    }
  } catch (erro) {
    throw new Error(messages.ExcecoesMensagens.erroAoDeletar(String(fileCaminho), (erro as Error).message));
  }
}

/**
 * Lista todos os arquivos JSON em um diretório do registry
 *
 * @param dirPath Caminho do diretório (use PROMETHEUS_DIRS.*)
 * @returns Lista de caminhos completos
 */
export async function listJSONFiles(dirPath: string): Promise<string[]> {
  try {
    const exists = await fileExists(dirPath);
    if (!exists) {
      return [];
    }
    const entries = await fs.readdir(dirPath, {
      withFileTypes: true
    });
    const jsonArquivos = entries.filter(entry => entry.isFile() && entry.name.endsWith('.json')).map(entry => path.join(dirPath, entry.name));
    return jsonArquivos;
  } catch (erro) {
    log.aviso(`Erro ao listar arquivos em ${dirPath}: ${(erro as Error).message}`);
    return [];
  }
}

/**
 * Exporta funções auxiliares para compatibilidade com código existente
 */
export const ArquivoRegistro = {
  read: readJSON,
  write: writeJSON,
  delete: deleteJSON,
  list: listJSONFiles,
  paths: PROMETHEUS_ARQUIVOS,
  dirs: PROMETHEUS_DIRS
} as const;

